import '../scss/index.scss';
import { Tooltip } from 'bootstrap';
import knowledge from '../json/knowledge';
import icons from '../img/icon/*.svg';
import iconsPng from '../img/icon/*.png';

Object.assign(icons, iconsPng);

(async function () {
	const myEml = 'pilaton.ever*aleeas.com'.replace('*', '@');
	const myEmailBlock = document.querySelector('#my_eml');

	let myEmailBlockTooltip = new Tooltip(myEmailBlock);

	myEmailBlock.addEventListener('click', (ev) => {
		ev.preventDefault();
		window.navigator.clipboard.writeText(myEml);

		myEmailBlockTooltip.disable();
		ev.currentTarget.setAttribute('data-bs-original-title', 'Copied!');
		myEmailBlockTooltip.enable();
		myEmailBlockTooltip.show();
		ev.currentTarget.setAttribute('data-bs-original-title', 'Copy to clipboard');

		ev.currentTarget.addEventListener('mouseleave', () => {
			myEmailBlockTooltip.hide();
		});
	});
})();

const knowledgeBaseList = document.querySelector('.knowledge_base-list');

Object.keys(knowledge)
	.sort()
	.forEach((key) => {
		const iconName = knowledge[key];

		let like = key == 'JavaScript';

		let div = `
			<div ${like ? 'class="like"' : ''}>
				<img src="${icons[iconName]}" alt="${key}">
				${key}

				${like ? '<i class="fa-regular fa-heart"></i>' : ''}
			</div>
		`;

		knowledgeBaseList.insertAdjacentHTML('beforeend', div);
	});
knowledgeBaseList.insertAdjacentHTML('beforeend', `<div>Other...</div>`);
